import { escapeHtml } from "../safeHtml.js";
import { icon } from "./icons.js";
export const timeline = (vm) => `<section class="panel timeline-panel"><div class="panel-head"><div><h2>Replay Event Timeline</h2><p>Chronological replay of captured events</p></div><div class="panel-actions"><button data-filter="all">${icon("filter")}All</button><button data-filter="warnings">${icon("warn")}Issues</button></div></div><div class="timeline-list">${vm.timeline.map((ev, i) => `<button class="timeline-row ${ev.status} ${i === 0 ? "selected" : ""}" data-event-index="${i}"><time>${escapeHtml(ev.timestamp ?? "—")}</time><span class="rail"><i>${icon(ev.status === "failed" ? "x" : ev.status === "warning" ? "warn" : "check")}</i></span><article><span class="row-icon">${icon(ev.icon)}</span><div><strong>${escapeHtml(ev.title)}</strong><p>${escapeHtml(ev.subtitle)}</p></div><em>${escapeHtml(ev.durationLabel)}</em></article></button>`).join("")}</div></section>`;
